// import React from 'react';
import styled from 'styled-components';
// import { Link as LinkR } from 'react-router-dom';
import { Link as LinkS } from 'react-scroll';

export const Nav = styled.nav`
  background-color: #808080;
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 100px;
  position: sticky;
  top: 0;
  z-index: 2;
  position: sticky;

  /* display: block; */
`;

export const NavbarContainer = styled.nav`
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 100px;
  width: 100%;
  z-index: 1;
  padding-left: 50px;

  /* max-width: 1100px; */
`;

export const NavLogo = styled(LinkS)`
  color: #fff;
  cursor: pointer;
  font-size: 1.5rem;
  display: flex;
  justify-self: flex-start;
  align-items: center;
  font-weight: bold;
  text-decoration: none;
`;

export const NavHamburgerIcon = styled.div`
  display: none;
  @media (max-width: 768px) {
    display: block;
    position: absolute;
    top: 10;
    right: 0;
    padding: 0 30px;
    transform: translate(-100, 60%);
    font-size: 1.8rem;
    cursor: pointer;
  }
`;

export const NavMenu = styled.ul`
  height: 100%;
  display: flex;
  align-items: center;
  list-style: none;
  justify-content: flex-end;
`;

export const NavItemContainer = styled.li`
  display: none;

  @media (min-width: 769px) {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    align-items: center;
    margin-right: 30px;
    height: 80px;
    padding: 0 1rem;
    text-decoration: none;
    height: 100%;
  }
`;

export const NavItem = styled(LinkS)`
  /* height: 100%; */
  cursor: pointer;
  font-size: 1.3em;
  color: #f1f1f1;
  padding-bottom: 12px;

  &.active {
    border-bottom: 3px solid #ffbc00;
    padding-bottom: 15px;
  }
`;
