import React, { useEffect } from 'react';
import { Container } from '../ui/Containers';
import { useInView } from 'react-intersection-observer';
import { useAnimation } from 'framer-motion';
import { ThemeProvider } from 'styled-components';

import {
  SkillsItemContainer,
  SkillsShowcaseContainer,
  SkillsShowcaseItem,
  TextItem,
  TextItemR,
} from './SkillsStyled';
import {
  SiJavascript,
  SiReact,
  SiTypescript,
  SiFramer,
  SiStyledcomponents,
  // SiNextdotjs,
  SiMaterialui,
  SiRedux,
  SiNodedotjs,
  SiExpress,
  SiMongodb,
  SiPostgresql,
  SiGreensock,
} from 'react-icons/si';

const ContainerVariant = {
  hidden: { x: '-100%', opacity: 0 },
  visible: {
    x: 0,
    opacity: 1,

    transition: {
      type: 'tween',
      // stiffness: 10,
      duration: 1,
      delay: 1,

      ease: 'easeInOut',
      staggerChildren: 0.3,
      when: 'beforeChildren',
    },
  },
};

const CardVariant = {
  hidden: { y: '20%', opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,

    transition: {
      duration: 0.5,
      ease: 'easeOut',
    },
  },
};
const TextVariant = {
  hidden2: { opacity: 0 },
  visible2: {
    opacity: 1,

    transition: {
      delay: 0.5,
      duration: 5,
      ease: 'easeOut',
    },
  },
};

const theme = {
  bgColor: 'var(--dark-color)',
  color: 'var(--light-color)',
};

const SkillsCover = () => {
  const { ref, inView } = useInView();

  const animationOne = useAnimation();
  const animationTwo = useAnimation();

  useEffect(() => {
    if (inView) {
      animationOne.start('visible');
      animationTwo.start('visible2');
    }
    if (!inView) {
      animationOne.start('hidden');
      animationTwo.start('hidden2');
    }
  }, [animationOne, animationTwo, inView]);

  const hoverObj = {
    scale: 1.1,
    originY: 1,
    originX: 1,
    // transition: { type: 'spring' },
  };

  return (
    <ThemeProvider theme={theme}>
      <Container id='skills' ref={ref}>
        {/* <ContainerAbsL /> */}
        <SkillsItemContainer>
          <TextItemR
            variants={TextVariant}
            initial='hidden2'
            animate={animationTwo}
          >
            DEV
          </TextItemR>
          <SkillsShowcaseContainer
            variants={ContainerVariant}
            initial='hidden'
            animate={animationOne}
          >
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiJavascript />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiReact />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiTypescript />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiRedux />
            </SkillsShowcaseItem>

            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiMaterialui />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiStyledcomponents />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiFramer />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiGreensock />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiNodedotjs />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiExpress />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiMongodb />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiPostgresql />
            </SkillsShowcaseItem>
          </SkillsShowcaseContainer>

          <TextItem
            variants={TextVariant}
            initial='hidden2'
            animate={animationTwo}
          >
            DEV
          </TextItem>
        </SkillsItemContainer>
      </Container>
    </ThemeProvider>
  );
};

export default SkillsCover;
