import { useEffect } from 'react';
import BackgroundImage from '../assets/pictures/FormalPic.jpg';
import { BottomLine } from '../ui/Lines';
import { GoldButton } from '../ui/Buttons';
import { useInView } from 'react-intersection-observer';
import { motion, useAnimation } from 'framer-motion';

import { AboutInfo, Bio, AboutImage, AboutInfoMobile } from './AboutStyled';

import { ThemeProvider } from 'styled-components';
import { ContainerBackground, Header } from '../ui/Containers';

const HeaderVariant = {
  hidden: { y: '50%', opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      duration: 0.5,
      delay: 0.8,
      ease: 'easeOut',
    },
  },
};
const ImageVariant = {
  hidden2: { y: '5%', x: '5%', opacity: 0 },
  visible2: {
    y: 0,
    x: 0,
    opacity: 1,
    transition: {
      duration: 2,
      delay: 1,
      ease: 'easeOut',
    },
  },
};
const BioVariant = {
  hidden3: { opacity: 0 },
  visible3: {
    opacity: 1,
    transition: {
      duration: 1,
      delay: 2,
      ease: 'easeOut',
    },
  },
};

const theme = {
  bgColor: '',
  color: 'var(--dark-color)',
};

const About: React.FC = () => {
  const { ref, inView } = useInView();

  const animationOne = useAnimation();
  const animationTwo = useAnimation();
  const animationThree = useAnimation();

  useEffect(() => {
    if (inView) {
      animationOne.start('visible');
      animationTwo.start('visible2');
      animationThree.start('visible3');
    }
    if (!inView) {
      animationOne.start('hidden');
      animationTwo.start('hidden2');
      animationThree.start('hidden3');
    }
  }, [animationOne, animationTwo, animationThree, inView]);
  // const openInNewTab = () => {
  //   window.open('../assets/pictures/Mountain2.jpg', '_blank')?.focus();
  // };

  return (
    <div ref={ref}>
      <ThemeProvider theme={theme}>
        <ContainerBackground id='about'>
          <Header>
            <motion.h1
              variants={HeaderVariant}
              initial='hidden'
              animate={animationOne}
            >
              About Me
            </motion.h1>
            <BottomLine />
          </Header>

          <AboutInfo>
            <motion.div
              variants={ImageVariant}
              initial='hidden2'
              animate={animationTwo}
            >
              <AboutImage src={BackgroundImage} alt='' />
            </motion.div>
            <Bio
              variants={BioVariant}
              initial='hidden3'
              animate={animationThree}
            >
              Hi! my name is Vanz. A Graduate of a Bachelor`s degree in
              Information Technology. Currently working as a Software engineer
              with experience in Frontend development and Software automation.
              Actively learning new technologies.
              <a href={process.env.PUBLIC_URL + `/files/resume.pdf`} download>
                <GoldButton>View my CV</GoldButton>
              </a>
            </Bio>

            {/* <img src={ProfileImage} alt='test/> */}
          </AboutInfo>
          <AboutInfoMobile>
            <motion.div
              variants={ImageVariant}
              initial='hidden2'
              animate={animationTwo}
            >
              <AboutImage src={BackgroundImage} alt='' />
            </motion.div>
            <Bio
              variants={BioVariant}
              initial='hidden3'
              animate={animationThree}
            >
              Hi! my name is Vanz. A Graduate of a Bachelor`s degree in
              Information Technology. Currently working as a Software engineer
              with experience in Frontend development and Software automation.
              Actively learning new technologies.
              <a href={process.env.PUBLIC_URL + `/files/Resume.pdf`} download>
                <GoldButton>View my CV</GoldButton>
              </a>
            </Bio>
          </AboutInfoMobile>
        </ContainerBackground>
      </ThemeProvider>
    </div>
  );
};

export default About;
