import React, { useEffect } from 'react';
import { Container } from '../ui/Containers';
import { useInView } from 'react-intersection-observer';
import { useAnimation } from 'framer-motion';
import { ThemeProvider } from 'styled-components';
// import ALM from '../ui/SVG Icons/ALM';
import UFT from '../ui/SVG Icons/UFT';

import {
  SkillsItemContainer,
  SkillsShowcaseContainer,
  SkillsShowcaseItem,
  TextItem,
  TextItemR,
} from './SkillsStyled';
import { SiPostman, SiSelenium, SiCypress } from 'react-icons/si';

const ContainerVariant = {
  hidden: { x: '100%', opacity: 0 },
  visible: {
    x: 0,
    opacity: 1,

    transition: {
      type: 'tween',
      // stiffness: 10,
      duration: 1,
      delay: 1,

      ease: 'easeInOut',
      staggerChildren: 0.5,
      when: 'beforeChildren',
    },
  },
};

const CardVariant = {
  hidden: { y: '20%', opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,

    transition: {
      duration: 1,
      ease: 'easeOut',
    },
  },
};
const TextVariant = {
  hidden2: { opacity: 0 },
  visible2: {
    opacity: 1,

    transition: {
      delay: 0.5,
      duration: 5,
      ease: 'easeOut',
    },
  },
};

const theme = {
  bgColor: 'var(--dark-color)',
  color: 'var(--light-color)',
};

const SkillsCover = () => {
  const { ref, inView } = useInView();

  const animationOne = useAnimation();
  const animationTwo = useAnimation();

  useEffect(() => {
    if (inView) {
      animationOne.start('visible');
      animationTwo.start('visible2');
    }
    if (!inView) {
      animationOne.start('hidden');
      animationTwo.start('hidden2');
    }
  }, [animationOne, animationTwo, inView]);

  const hoverObj = {
    scale: 1.1,
    originY: 1,
    originX: 1,
    // transition: { type: 'spring' },
  };

  return (
    <ThemeProvider theme={theme}>
      <Container id='skills'>
        {/* <ContainerAbsR /> */}
        <SkillsItemContainer ref={ref}>
          <TextItem
            variants={TextVariant}
            initial='hidden2'
            animate={animationTwo}
          >
            QA
          </TextItem>
          <TextItemR
            variants={TextVariant}
            initial='hidden2'
            animate={animationTwo}
          >
            QA
          </TextItemR>
          <SkillsShowcaseContainer
            variants={ContainerVariant}
            initial='hidden'
            animate={animationOne}
          >
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiSelenium />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <UFT width={70} height={70} />
            </SkillsShowcaseItem>
            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiCypress />
            </SkillsShowcaseItem>

            <SkillsShowcaseItem variants={CardVariant} whileHover={hoverObj}>
              <SiPostman />
            </SkillsShowcaseItem>
          </SkillsShowcaseContainer>
        </SkillsItemContainer>
      </Container>
    </ThemeProvider>
  );
};

export default SkillsCover;
