import styled from 'styled-components';
import BackgroundImage from '../assets/svg/blob-scene-haikei.svg';

export const Header = styled.div`
  width: 100%;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  margin-bottom: 2rem;

  & h1 {
    text-align: center;
    font-size: 2rem;
  }
`;

export const Container = styled.section`
  background-color: ${(props) => props.theme.bgColor};
  color: ${(props) => props.theme.color};
  height: 900px;
  width: 100%;
  display: flex;
  flex-direction: column;
  justify-content: space-around;
  align-items: center;
  overflow: hidden;
  position: relative;
  z-index: 0;

  /* @media (max-height: 1024px) {
    display: none;
  } */
`;

export const ContainerMobile = styled.section`
  @media (max-width: 1024px) {
    background-color: ${(props) => props.theme.bgColor};
    color: ${(props) => props.theme.color};
    height: 1500px;
    width: 100%;
    display: flex;
    flex-direction: column;
    justify-content: space-evenly;
    align-items: center;
    overflow: hidden;
    position: relative;
    z-index: 0;
  }
  @media (min-width: 1025px) {
    background-color: ${(props) => props.theme.bgColor};
    color: ${(props) => props.theme.color};
    height: 900px;
    width: 100%;
    display: flex;
    flex-direction: column;
    justify-content: space-around;
    align-items: center;
    overflow: hidden;
    position: relative;
    z-index: 0;
  }
`;

export const ContainerBackground = styled.section`
  aspect-ratio: 900/540;

  width: 100%;
  padding-top: 5rem;
  overflow: hidden;

  /* background-image: '../assets/svg/blob-scene-haikei.svg'; */
  background-image: url(${BackgroundImage});

  background-repeat: no-repeat;
  background-position: center;
  background-size: cover;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;

  @media (min-width: 1024px) {
    height: 100vh;
  }
  @media (max-width: 1023px) {
    height: 130vh;
  }
`;

export const SkillsContainer = styled.div`
  background-color: ${(props) => props.theme.bgColor};
  color: ${(props) => props.theme.color};
  padding-top: 5rem;

  width: 100%;
  display: flex;
  flex-direction: column;
`;
