import React, { useState, useEffect, useRef, useContext } from 'react';

import { FaEnvelope, FaPhone, FaHome } from 'react-icons/fa';
import { LightButton } from '../ui/Buttons';
import { BottomLine } from '../ui/Lines';
import {
  ContactItemContainer,
  ContactFormContainer,
  ContactInfoContainer,
  ContactForm,
  InputTextField,
  ContactInfoCard,
  ContactTextGroup,
  IconContainer,
} from './ContactStyled';
import AuthContext from '../../store/auth-context';
import { ThemeProvider } from 'styled-components';
import { Header, ContainerMobile } from '../ui/Containers';
import { motion, useAnimation } from 'framer-motion';
import { useInView } from 'react-intersection-observer';

const HeaderVariant = {
  hidden: { y: '50%', opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      duration: 0.5,
      delay: 0.8,
      ease: 'easeOut',
    },
  },
};

const ContainerVariant = {
  hidden2: { opacity: 0 },
  visible2: {
    opacity: 1,

    transition: {
      type: 'spring',
      stiffness: 120,
      delay: 1,

      ease: 'easeInOut',
      staggerChildren: 0.5,
      when: 'beforeChildren',
    },
  },
};

const CardVariant = {
  hidden2: { x: '20%', opacity: 0 },
  visible2: {
    x: 0,
    opacity: 1,

    transition: {
      duration: 1,
      ease: 'easeOut',
    },
  },
};

const theme = {
  bgColor: 'var(--dark-color)',
  color: 'var(--light-color)',
};

const Contact = () => {
  const nameInputRef = useRef<HTMLInputElement>(null);
  const emailInputRef = useRef<HTMLInputElement>(null);
  const subjectInputRef = useRef<HTMLInputElement>(null);
  const messageInputRef = useRef<HTMLTextAreaElement>(null);

  const authCtx = useContext(AuthContext);

  const [nameInput, setNameInput] = useState('');
  const [emailInput, setEmailInput] = useState('');
  const [subjectInput, setSubjectInput] = useState('');
  const [messageInput, setMessageInput] = useState('');

  const { ref, inView } = useInView();

  const animationOne = useAnimation();
  const animationTwo = useAnimation();

  useEffect(() => {
    if (inView) {
      animationOne.start('visible');
      animationTwo.start('visible2');
    }
    if (!inView) {
      animationOne.start('hidden');
      animationTwo.start('hidden2');
    }
  }, [animationOne, animationTwo, inView]);

  const inputChangeHandler = () => {
    setNameInput(nameInputRef.current!.value);
    setEmailInput(emailInputRef.current!.value);
    setSubjectInput(subjectInputRef.current!.value);
    setMessageInput(messageInputRef.current!.value);
  };

  const submitHandler = (event: React.FormEvent) => {
    event.preventDefault();
    // const enterteredName = nameInputRef.current!.value; // guaranteed no null values (!)
    const enterteredName = nameInputRef.current!.value;
    const enterteredEmail = emailInputRef.current!.value;
    const enterteredSubject = subjectInputRef.current!.value;
    const enterteredMessage = messageInputRef.current!.value;

    setNameInput('');
    setEmailInput('');
    setSubjectInput('');
    setMessageInput('');

    authCtx.contact.name = enterteredName;
    authCtx.contact.name = enterteredEmail;
    authCtx.contact.subject = enterteredSubject;
    authCtx.contact.message = enterteredMessage;
  };

  return (
    <div ref={ref}>
      <ThemeProvider theme={theme}>
        <ContainerMobile id='contact'>
          <Header>
            <motion.h1
              variants={HeaderVariant}
              initial='hidden'
              animate={animationOne}
            >
              Contact
            </motion.h1>
            <BottomLine />
          </Header>
          <ContactItemContainer>
            <ContactFormContainer>
              <ContactForm
                action='contact'
                method='post'
                role='form'
                onSubmit={submitHandler}
              >
                <Header>
                  <h1>Get In Touch</h1>
                </Header>
                <InputTextField
                  type='text'
                  placeholder='Name'
                  id='name'
                  required
                  ref={nameInputRef}
                  value={nameInput}
                  onChange={inputChangeHandler}
                />
                <InputTextField
                  type='text'
                  placeholder='Email'
                  id='email'
                  required
                  ref={emailInputRef}
                  value={emailInput}
                  onChange={inputChangeHandler}
                />
                <InputTextField
                  type='text'
                  placeholder='Subject'
                  id='subject'
                  required
                  ref={subjectInputRef}
                  value={subjectInput}
                  onChange={inputChangeHandler}
                />
                <textarea
                  placeholder='Message'
                  id='message'
                  required
                  ref={messageInputRef}
                  value={messageInput}
                  onChange={inputChangeHandler}
                />
                <div>
                  <LightButton type='submit'>Submit</LightButton>
                </div>
              </ContactForm>
            </ContactFormContainer>

            <ContactInfoContainer
              variants={ContainerVariant}
              initial='hidden2'
              animate={animationTwo}
            >
              <ContactInfoCard variants={CardVariant}>
                <IconContainer>
                  <FaEnvelope />
                </IconContainer>
                <ContactTextGroup>
                  <label>Email</label>
                  <label>vc.lorenzo16@gmail.com</label>
                </ContactTextGroup>
              </ContactInfoCard>

              <ContactInfoCard variants={CardVariant}>
                <IconContainer>
                  <FaPhone />
                </IconContainer>
                <ContactTextGroup>
                  <label>Phone</label>
                  <label>09566452484</label>
                </ContactTextGroup>
              </ContactInfoCard>
              <ContactInfoCard variants={CardVariant}>
                <IconContainer>
                  <FaHome />
                </IconContainer>
                <ContactTextGroup>
                  <label>Address</label>
                  <label>Pasig, Ph</label>
                </ContactTextGroup>
              </ContactInfoCard>
            </ContactInfoContainer>
          </ContactItemContainer>
        </ContainerMobile>
      </ThemeProvider>
    </div>
  );
};

export default Contact;
