import styled from 'styled-components';

export const LightButton = styled.button`
  /* user-select: none;
  transition: background 20ms ease-in 0s; */
  cursor: pointer;
  height: 3.5rem;
  border-radius: 3px;
  color: #333;
  font-size: 0.8rem;

  font-weight: 500;
  background: #f4f4f4;
  box-shadow: rgb(15 15 15 / 10%) 0px 1px 2px,
    rgb(235 87 87 / 30%) 0px 0px 0px 1px inset;

  width: 150px;

  &:hover {
    background-color: var(--main-color);
  }
`;
export const GoldButton = styled.button`
  /* user-select: none;
  transition: background 20ms ease-in 0s; */
  cursor: pointer;
  height: 3rem;
  border: 1px var(--main-color) solid;
  border-radius: 50px;
  color: var(--main-color);
  background-color: transparent;
  font-size: 0.8rem;

  font-weight: 500;
  box-shadow: rgb(15 15 15 / 10%) 0px 1px 2px,
    rgb(235 87 87 / 30%) 0px 0px 0px 1px inset;

  width: 120px;

  &:hover {
    border: transparent;
    background-color: var(--main-color);
    color: var(--light-color);
  }
`;
export const GoldChip = styled.button`
  /* user-select: none;
  transition: background 20ms ease-in 0s; */
  cursor: pointer;
  height: 2rem;
  width: 100px;
  border: 1px var(--main-color) solid;
  border-radius: 50px;
  color: var(--main-color);
  background-color: transparent;
  font-size: 0.8rem;

  font-weight: 500;
  box-shadow: rgb(15 15 15 / 10%) 0px 1px 2px,
    rgb(235 87 87 / 30%) 0px 0px 0px 1px inset;
`;
