import { motion, useAnimation } from 'framer-motion';
import React, { useEffect } from 'react';
import { ThemeProvider } from 'styled-components';
// import AuthContext from '../../store/auth-context';
import WorkImage from '../assets/pictures/connector2.jpg';
// import ModalWork from '../Modal/ModalWork';
import { Container, Header } from '../ui/Containers';
import { BottomLine } from '../ui/Lines';
import { WorkInfoContainer, WorkInfoContent } from './WorkStyled';
import { useInView } from 'react-intersection-observer';

const HeaderVariant = {
  hidden: { y: '50%', opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      duration: 0.5,
      delay: 0.8,
      ease: 'easeOut',
    },
  },
};

const InfoVariant = {
  hidden: { y: '-20%', opacity: 0 },
  visible: {
    y: '0',
    opacity: 1,

    transition: {
      delay: 0.5,
      duration: 1,
      ease: 'easeInOut',
    },
  },
};

const theme = {
  bgColor: '',
  color: 'var(--light-color)',
};

const Work: React.FC = () => {
  // const authCtx = useContext(AuthContext);

  const { ref, inView } = useInView();

  const animationOne = useAnimation();
  const animationTwo = useAnimation();

  useEffect(() => {
    if (inView) {
      animationOne.start('visible');
      animationTwo.start('visible');
    }
    if (!inView) {
      animationOne.start('hidden');
      animationTwo.start('hidden');
    }
  }, [animationOne, animationTwo, inView]);

  return (
    <div ref={ref}>
      <ThemeProvider theme={theme}>
        {/* {authCtx.showModal && <Modal />} */}
        {/* <AnimatePresence>{authCtx.showModal && <ModalWork />}</AnimatePresence> */}

        <Container id='work'>
          <Header>
            <motion.h1
              variants={HeaderVariant}
              initial='hidden'
              animate={animationOne}
            >
              Featured Projects
            </motion.h1>
            <BottomLine />
          </Header>
          <WorkInfoContainer
            variants={InfoVariant}
            initial='hidden'
            animate={animationTwo}
          >
            {/* <WorkInfoContent onClick={authCtx.toggleModalWork}> */}
            <a
              href='https://job-avenue.herokuapp.com/login'
              target='_blank'
              rel='noreferrer noopener'
            >
              <WorkInfoContent>
                {/* <WorkInfoContent onClick={}> */}

                <img src={WorkImage} alt='' />

                <p>DevConnector </p>
              </WorkInfoContent>
            </a>
          </WorkInfoContainer>
        </Container>
      </ThemeProvider>
    </div>
  );
};

export default Work;
