// import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

export const ContactItemContainer = styled.div`
  @media (min-width: 1441px) {
    background-color: #333;
    width: 100%;

    display: grid;
    grid-template-columns: repeat(2, 1fr);
    align-items: center;
    padding: 0 10rem;
  }

  @media (min-width: 1201px) and (max-width: 1440px) {
    background-color: #333;
    width: 100%;

    display: grid;
    grid-template-columns: repeat(2, 1fr);
    align-items: center;
    padding: 0 5rem;
  }

  //Mobile
  @media (max-width: 1200px) {
    background-color: #333;
    width: 100%;

    display: flex;
    flex-direction: column;

    gap: 5rem;

    align-items: center;
  }
`;

export const ContactFormContainer = styled(motion.div)`
  /* border: 3px var(--dark-color) solid;
  border-radius: 10px; */

  & h1 {
    color: var(--dark-color);
  }

  //WideScreen
  @media (min-width: 1441px) {
    background-color: var(--base-color);
    width: 100%;
    display: flex;
    flex-direction: column;
    padding: 2rem 50px;
    border-radius: 10px;
  }

  //Laptop
  @media (min-width: 1025px) and (max-width: 1440px) {
    padding: 2rem 30px;

    background-color: var(--base-color);
    /* height: 600px; */
    width: 100%;
    display: flex;
    flex-direction: column;
    border-radius: 10px;
  }
`;

export const ContactForm = styled.form`
  //Laptop
  @media (min-width: 1025px) {
    background-color: var(--base-color);

    height: 500px;
    width: 100%;
    margin: 1rem auto;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;

    & textarea {
      height: 150px;
      border: 1px black solid;
      padding: 0.5rem 1rem;
    }
    & div {
      margin: auto;
    }
  }

  @media (max-width: 500px) {
    background-color: var(--base-color);
    /* opacity: 50%; */
    height: 500px;
    width: 35rem;
    padding: 2rem 150px;

    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    border-radius: 5px;

    & textarea {
      height: 150px;
      border: 1px black solid;
      /* display: block; */
      padding: 0.5rem 1rem;
    }
    & div {
      margin: auto;
    }
  }
  @media (min-width: 501px) and (max-width: 768px) {
    background-color: var(--base-color);
    /* opacity: 50%; */
    height: 500px;
    width: 50rem;
    padding: 2rem 150px;

    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    border-radius: 5px;

    & textarea {
      height: 150px;
      border: 1px black solid;
      /* display: block; */
      padding: 0.5rem 1rem;
    }
    & div {
      margin: auto;
    }
  }

  @media (min-width: 769px) and (max-width: 1024px) {
    background-color: var(--base-color);
    /* opacity: 50%; */
    height: 500px;
    width: 70rem;
    padding: 2rem 150px;

    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    border-radius: 5px;

    & textarea {
      height: 150px;
      border: 1px black solid;
      /* display: block; */
      padding: 0.5rem 1rem;
    }
    & div {
      margin: auto;
    }
  }
`;

export const InputTextField = styled.input`
  border: 1px black solid;
  padding: 0.5rem 1rem;
`;

export const ContactInfoContainer = styled(motion.div)`
  background-color: var(--dark-color);
  height: 600px;
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 2rem;
  text-align: center;
  justify-content: center;
  align-items: center;
  /* justify-content: space-around; */
`;

export const ContactInfoCard = styled(motion.div)`
  @media (max-width: 1200px) {
    padding: 2rem 2rem;
    border: 2px solid var(--light-color);
    opacity: 60%;
    color: var(--dark-color);
    min-width: 90%;
    height: 40%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    text-align: center;
    gap: 2rem;
    border-radius: 5px;
    & svg {
      fill: var(--light-color);
    }
  }

  @media (min-width: 1201px) {
    padding: 2rem 2rem;
    border: 2px solid var(--light-color);
    opacity: 60%;
    color: var(--dark-color);
    min-width: 450px;
    display: flex;
    flex-direction: row;
    justify-content: left;
    gap: 2.5rem;
    border-radius: 5px;
    & svg {
      fill: var(--light-color);
    }
  }
`;

export const ContactTextGroup = styled.div`
  @media (max-width: 1200px) {
    display: flex;
    flex-direction: column;
    /* gap: 0.5rem; */
    justify-content: center;
    align-items: center;
    font-size: 1rem;
    font-weight: 700;
    color: var(--light-color);
    /* text-align: left; */
  }

  @media (min-width: 1201px) {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    justify-content: center;
    align-items: flex-start;
    font-size: 1rem;
    font-weight: 700;
    color: var(--light-color);
    /* text-align: left; */
  }
`;

//==================================================================

export const IconContainer = styled.div`
  @media (max-width: 1200px) {
    font-size: 1.5rem;
    height: 70px;
    width: 70px;
    color: var(--light-color);
    display: flex;
    justify-content: center;
    align-items: center;
    margin: auto 0;
    /* margin-bottom: 5px; */
    border: 2px var(--light-color) solid;
    border-radius: 10px;
  }

  @media (min-width: 1201px) {
    font-size: 2rem;
    height: 100px;
    width: 100px;
    color: var(--light-color);
    display: flex;
    justify-content: center;
    align-items: center;
    margin: auto 0;
    margin-left: 2rem;
    /* margin-bottom: 5px; */
    border: 2px var(--light-color) solid;
    border-radius: 10px;
  }
`;
