import styled from 'styled-components';

export const IntroContainer = styled.section`
  display: flex;
  flex-direction: column;
  gap: 2rem;
  color: white;
  font-size: 2rem;
  font-weight: 500;

  margin: auto;
  align-items: center;
  justify-content: center;
  height: 900px;
  width: 100%;
  position: relative;
`;

export const VideoBg = styled.video`
  height: 100%;
  width: 100%;
  object-fit: cover;
  -o-object-fit: fill;
  position: absolute;
  z-index: -1;
  top: 0;
  /* right: auto; */
`;

export const IntroTextItems = styled.div`
  & h1 {
    font-size: 3rem;
    font-weight: bold;
  }
`;
