import styled from 'styled-components';
import { motion } from 'framer-motion';

export const SkillsItemContainer = styled(motion.div)`
  @media (min-width: 1025px) {
    background-color: ${(props) => props.theme.bgColor};
    color: ${(props) => props.theme.color};
    width: 100%;
    height: 100%;

    justify-content: center;
    align-items: center;
    display: grid;
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 1024px) {
    background-color: ${(props) => props.theme.bgColor};
    color: ${(props) => props.theme.color};
    width: 100%;
    height: 100%;

    justify-content: center;
    align-items: center;

    text-align: center;
    font-size: 8rem;
    display: flex;
    flex-direction: column;
    /* grid-template-columns: repeat(2, 1fr); */
  }
`;

export const SkillsShowcaseContainer = styled(motion.div)`
  height: 100%;
  width: 100%;
  padding: 10rem 0;
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  align-items: center;
  justify-items: center;

  background-color: var(--main-color);
`;

export const SkillsShowcaseItem = styled(motion.div)`
  @media (max-width: 500px) {
    font-size: 4rem;
    font-weight: bold;
    height: 60px;
    width: 60px;
    display: flex;
    justify-content: center;
    align-items: center;
    & svg {
      fill: ${(props) => props.theme.bgColor};
    }
  }
  @media (min-width: 501px) and (max-width: 1024px) {
    font-size: 4rem;
    font-weight: bold;
    height: 100px;
    width: 100px;
    grid-template-columns: repeat(2, 1fr);

    display: flex;
    justify-content: center;
    align-items: center;
    & svg {
      fill: ${(props) => props.theme.bgColor};
    }
  }

  @media (min-width: 1025px) and (max-width: 1440px) {
    font-size: 4rem;
    font-weight: bold;
    height: 150px;
    width: 150px;
    padding: 10px 10px;
    border: 4px solid ${(props) => props.theme.bgColor};
    display: flex;
    justify-content: center;
    align-items: center;
    & svg {
      fill: ${(props) => props.theme.bgColor};
    }
  }
  @media (min-width: 1441px) {
    font-size: 4rem;
    font-weight: bold;
    height: 150px;
    width: 150px;
    padding: 10px 10px;
    border: 4px solid ${(props) => props.theme.bgColor};
    display: flex;
    justify-content: center;
    align-items: center;
    & svg {
      fill: ${(props) => props.theme.bgColor};
    }
  }
`;

export const TextItem = styled(motion.h1)`
  text-align: center;
  font-size: 15rem;
  @media (max-width: 1024px) {
    display: none;
  }
`;
export const TextItemR = styled(motion.h1)`
  text-align: center;
  @media (max-width: 500px) {
    font-size: 10rem;
  }

  @media (min-width: 1025px) {
    display: none;
    font-size: 15rem;
  }
`;
