import React, { useContext } from 'react';
import ReactDOM from 'react-dom';
import styled from 'styled-components';
// import { FaAngleLeft, FaAngleRight } from 'react-icons/fa';
import { IoClose } from 'react-icons/io5';
// import Image from '../assets/pictures/Mountain1.jpg';

import { Link as LinkS } from 'react-scroll';
import AuthContext from '../../store/auth-context';
import { motion } from 'framer-motion';

const Backdrop = styled(motion.div)`
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100vh;
  z-index: 10;
  background: rgba(0, 0, 0, 0.75);
`;

const ModalOverlay = styled(motion.div)`
  position: fixed;
  top: 5%;
  bottom: 5%;
  left: 5%;
  right: 5%;
  width: 90%;
  height: 90%;
  margin: auto;
  z-index: 100;
  background: var(--base-color);
  padding: 1rem 1rem 2rem 1rem;

  display: flex;
  flex-direction: column;
  justify-content: space-between;
  /* align-items: center; */

  /* gap: 0.5rem; */

  /* overflow: hidden; */
`;

// const ModalOverlay = ()=>{
//     return<div/>

// };

export const ModalItemContainer = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: space-evenly;
  align-items: center;
  height: 100%;
`;

export const NavItem = styled(LinkS)`
  cursor: pointer;
  font-size: 2em;
  font-weight: bolder;
  color: var(--dark-color);
  height: 8rem;
  width: 80%;
  display: flex;
  justify-content: center;
  align-items: center;
  border: 5px solid var(--dark-color);
`;

export const IconContainer = styled.div`
  font-size: 3rem;
  display: flex;
  justify-content: center;
  align-items: center;
  margin: auto;

  & svg {
    fill: var(--dark-color);
    opacity: 70%;
  }
`;

export const Close = styled.div`
  /* display: block; */
  display: flex;
  justify-content: flex-end;
  & svg {
    fill: var(--dark-color);
    font-size: 2rem;
  }
`;

const backdropVariant = {
  visible: { opacity: 1 },
  hidden: { opacity: 0 },
};
const modalVariant = {
  hidden: { y: '-100vh', opacity: 0 },
  visible: { y: '0', opacity: 1, transition: { delay: 0.5 } },
};

const ModalNav = () => {
  const authCtx = useContext(AuthContext);

  return (
    <>
      {ReactDOM.createPortal(
        <Backdrop
          key='backdrop'
          variants={backdropVariant}
          initial='hidden'
          animate='visible'
          exit='hidden'
        />,
        document.getElementById('backdrop-root')!
      )}
      {ReactDOM.createPortal(
        <ModalOverlay
          variants={modalVariant}
          initial='hidden'
          animate='visible'
          exit='hidden'
        >
          <Close>
            <IoClose onClick={authCtx.toggleModalNav} />
          </Close>
          <ModalItemContainer>
            <NavItem
              to='about'
              spy={true}
              smooth={true}
              offset={-70}
              duration={500}
              onClick={authCtx.toggleModalNav}
            >
              About
            </NavItem>

            <NavItem
              to='skills'
              spy={true}
              smooth={true}
              offset={-70}
              duration={500}
              onClick={authCtx.toggleModalNav}
            >
              Skills
            </NavItem>

            <NavItem
              to='work'
              spy={true}
              smooth={true}
              offset={-70}
              duration={500}
              onClick={authCtx.toggleModalNav}
            >
              Work
            </NavItem>

            <NavItem
              to='contact'
              spy={true}
              smooth={true}
              offset={-70}
              duration={500}
              onClick={authCtx.toggleModalNav}
            >
              Contact
            </NavItem>
          </ModalItemContainer>
        </ModalOverlay>,
        document.getElementById('overlay-root')!
      )}
    </>
  );
};
export default ModalNav;
