// import React from 'react';
import styled from 'styled-components';

export const FooterContainer = styled.footer`
  /* position: fixed;
  bottom: 0; */
  height: 150px;
  width: 100%;
  padding: 0 70px;
  display: flex;
  justify-content: space-between;
  align-items: center;

  background-color: #808080;
  @media (max-width: 500px) {
    font-size: 1rem;
    flex-direction: column;
    justify-content: space-evenly;
  }

  @media (min-width: 501px) and (max-width: 768px) {
    font-size: 1.3rem;
    flex-direction: column;
    justify-content: space-evenly;
  }
`;

export const FooterMenu = styled.ul`
  display: flex;

  list-style: none;
  justify-content: flex-start;
`;

export const FooterItemContainer = styled.li`
  @media (max-width: 500px) {
    margin-right: 0;
    padding: 20px;
  }
  @media (min-width: 501px) and (max-width: 768px) {
    margin-right: 0;
    padding: 30px;
  }

  display: flex;
  align-items: center;
  justify-content: center;
  margin-right: 30px;
  height: 80px;
  /* padding: 0 1rem; */

  text-decoration: none;

  & a {
    display: flex;
    align-items: center;
  }
`;

export const FooterItem = styled.div`
  display: flex;
  align-items: center;
  justify-content: center;
  margin: auto;
  height: 50px;
  width: 50px;
  cursor: pointer;
  font-size: 1.5rem;
  border: 2px solid var(--light-color);
  border-radius: 50%;
  & svg {
    fill: var(--light-color);
  }

  &:hover {
    border: 2px solid var(--main-color);

    & svg {
      fill: var(--main-color);
    }
  }
`;

export const FooterCopyright = styled.div`
  color: #fff;
  display: flex;
  justify-self: flex-end;

  @media (max-width: 500px) {
    font-size: 0.7rem;
    text-align: center;
  }
  @media (min-width: 501px) and (max-width: 768) {
    font-size: 1rem;
    text-align: center;
  }

  @media (min-width: 769px) {
    font-size: 1.5rem;
    text-align: center;
  }
  /* align-items: center; */
`;
