import React, { useContext } from 'react';
import AuthContext from '../../store/auth-context';
import ModalNav from '../Modal/ModalNav';
import { animateScroll } from 'react-scroll';
// import { NavLink } from 'react-router-dom';
import { FaBars } from 'react-icons/fa';
import {
  NavbarContainer,
  NavLogo,
  NavHamburgerIcon,
  NavMenu,
  NavItemContainer,
  NavItem,
  Nav,
} from './NavbarStyled';

const Navbar: React.FC = () => {
  const authCtx = useContext(AuthContext);
  // useEffect(()=>{

  // },[])

  const scrollToTopHandler = () => {
    animateScroll.scrollToTop();
  };

  return (
    <>
      {authCtx.showModal && <ModalNav />}
      <Nav>
        <NavbarContainer>
          <NavLogo to='/' onClick={scrollToTopHandler}>
            VL
          </NavLogo>
          <NavHamburgerIcon onClick={authCtx.toggleModalNav}>
            <FaBars />
          </NavHamburgerIcon>
          <NavMenu>
            <NavItemContainer>
              <div />
              <NavItem
                to='about'
                spy={true}
                smooth={true}
                offset={-70}
                duration={500}
              >
                About
              </NavItem>
            </NavItemContainer>
            <NavItemContainer>
              <div></div>
              <NavItem
                to='skills'
                spy={true}
                smooth={true}
                offset={-70}
                duration={500}
              >
                Skills
              </NavItem>
            </NavItemContainer>
            <NavItemContainer>
              <div></div>
              <NavItem
                to='work'
                spy={true}
                smooth={true}
                offset={-70}
                duration={500}
              >
                Work
              </NavItem>
            </NavItemContainer>
            <NavItemContainer>
              <div></div>
              <NavItem
                to='contact'
                spy={true}
                smooth={true}
                offset={-70}
                duration={500}
              >
                Contact
              </NavItem>
            </NavItemContainer>
          </NavMenu>
        </NavbarContainer>
      </Nav>
    </>
  );
};

export default Navbar;
