// import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';

export const AboutInfo = styled.div`
  display: none;
  @media (min-width: 769px) {
    /* background-color: #fffefc; */
    width: 100%;
    align-items: center;
    padding: 0 15rem;
    min-height: 500px;

    display: grid;
    /* grid-gap: 2rem; */
    grid-template-columns: repeat(2, 1fr);

    & div {
      display: flex;
      justify-self: center;
    }
  }
`;
export const AboutInfoMobile = styled.div`
  display: none;
  @media (max-width: 768px) {
    display: grid;
    grid-template-rows: repeat(2, 50%);
    padding: 10rem 0;
    & div {
      display: flex;
      justify-self: center;
    }
  }
`;

export const AboutImage = styled.img`
  @media (max-width: 768px) {
    max-width: 15rem;
    max-height: 15rem;

    object-fit: fill;
    border-radius: 50%;
  }
  @media (min-width: 769px) {
    max-width: 70%;
    max-height: 70rem;
    object-fit: fill;
    border-radius: 50%;
  }
`;

export const Bio = styled(motion.div)`
  //Mobile
  @media (max-width: 768px) {
    display: flex;
    flex-direction: column;
    justify-content: space-evenly;
    gap: 1.5rem;
    background-color: var(--light-color);
    color: var(--dark-color);
    /* border-left: 3px solid #ffbc00; */
    padding: 0 1rem;

    font-size: 1.3rem;
    text-align: left;
    line-height: 2.5rem;
    min-height: 400px;
    width: 100%;
  }
  @media (min-width: 769px) {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    background-color: var(--light-color);
    color: var(--dark-color);
    border-left: 3px solid #ffbc00;
    padding: 3rem;
    font-size: 1.5rem;
    text-align: left;
    line-height: 2.5;
    /* min-height: ; */
    width: 800px;
  }
`;

