import React, { useEffect } from 'react';
import SkillsQA from './SkillsQA';
import SkillsDev from './SkillsDev';
import { ThemeProvider } from 'styled-components';
import { useAnimation } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
// import SkillsShowcase from './SkillsShowcase';
// import HorizontalScroll from 'react-scroll-horizontal';
// import { SkillsContainer } from './SkillsStyled';
import { Header } from '../ui/Containers';
import { BottomLine } from '../ui/Lines';
import { motion } from 'framer-motion';
import { SkillsContainer } from '../ui/Containers';

const HeaderVariant = {
  hidden: { y: '50%', opacity: 0 },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      duration: 0.5,
      delay: 0.8,
      ease: 'easeOut',
    },
  },
};

const theme = {
  bgColor: 'var(--dark-color)',
  color: 'var(--light-color)',
};

const Skills: React.FC = (props) => {
  const { ref, inView } = useInView();

  const animationOne = useAnimation();

  useEffect(() => {
    // console.log('Inview =', inView);
    if (inView) {
      animationOne.start('visible');
    }
    if (!inView) {
      animationOne.start('hidden');
    }
  }, [animationOne, inView]);

  return (
    <div ref={ref}>
      <ThemeProvider theme={theme}>
        <SkillsContainer id='skills'>
          <Header>
            <motion.h1
              variants={HeaderVariant}
              initial='hidden'
              animate={animationOne}
            >
              Skills
            </motion.h1>
            <BottomLine />
          </Header>

          <SkillsQA />

          <SkillsDev />
        </SkillsContainer>
      </ThemeProvider>
    </div>
  );
};

export default Skills;
