import React from 'react';
import { Container } from '../ui/Containers';
import Video from '../assets/videos/bokeh.mp4';
import { LightButton } from '../ui/Buttons';
import { scroller as Scroll } from 'react-scroll';
import Typewriter from 'typewriter-effect';
import { IntroContainer, VideoBg, IntroTextItems } from './IntroStyled';

const Intro = () => {
  const scrollToSection = () => {
    Scroll.scrollTo('work', {
      duration: 500,
      offset: -70,
      smooth: 'true',
    });
  };
  return (
    <>
      <Container>
        <IntroContainer>
          <VideoBg autoPlay loop muted src={Video} typeof='video/mp4' />

          <IntroTextItems>
            <h1>Vanz Lorenzo</h1>
          </IntroTextItems>
          <IntroTextItems>I specialize in</IntroTextItems>
          <Typewriter
            options={{
              strings: ['Test Automation', 'Frontend Development'],
              cursor: '',
              autoStart: true,
              loop: true,
            }}
          />
          <LightButton onClick={scrollToSection}>View My Work</LightButton>
        </IntroContainer>
      </Container>
    </>
  );
};

export default Intro;
